#!/usr/bin/env python3
# Piece 1c-B-cabinet v4 — the REAL fix. Built from the live deployed cabinet.js.
# Root cause (found by cloning the live repo): the deployed EVENT_SELECT still
# read `note` — the v2 "notes" fix never landed in the committed file. The events
# column is `notes` (plural); binders uses `note` (singular); selecting a column
# that doesn't exist threw the generic "Lookup failed". Confirmed the ONLY bug:
# binders SELECT is valid (date exists as a reserved-word column, fine bare in
# supabase-js, as Kriya selects it). Also folds in the diagnostic error handler
# that names which read failed + surfaces the message, so no future mystery.

import base64, os, sys
ROOT = os.getcwd()
CAB_B64 = ""
CORE = os.path.join(ROOT, "src", "api", "vendor", "core.js")
MOUNT_ANCHOR = "router.use('/context',  require('./context'));"
MOUNT_NEW    = ("router.use('/context',  require('./context'));\n"
                "router.use('/cabinet',  require('./cabinet'));")

def main():
    vdir = os.path.join(ROOT, "src", "api", "vendor")
    if not os.path.isdir(vdir):
        print("ERROR: run from dream-os repo root."); sys.exit(1)
    open(os.path.join(vdir, "cabinet.js"), "wb").write(base64.b64decode(CAB_B64))
    print("OK: wrote src/api/vendor/cabinet.js (note->notes fixed + diagnostic)")
    s = open(CORE, encoding="utf-8").read()
    if "require('./cabinet')" in s:
        print("OK: /cabinet already mounted")
    elif MOUNT_ANCHOR in s:
        open(CORE, "w", encoding="utf-8").write(s.replace(MOUNT_ANCHOR, MOUNT_NEW, 1))
        print("OK: mounted /cabinet")
    else:
        print("WARN: mount anchor not found"); sys.exit(1)
    print("\nv4 written. Re-curl the cabinet — events read will now succeed.")

if __name__ == "__main__":
    main()
